To proxy requests in an ASP.NET Core API, you can use the `HttpClient` class to make a request to the target endpoint and then return the response to the client. Here's an example of how you can implement this:

```csharp
[ApiController]
[Route("[controller]")]
public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet("{targetUrl}")]
    public async Task<IActionResult> ProxyRequest(string targetUrl)
    {
        var httpClient = _httpClientFactory.CreateClient();
        var request = new HttpRequestMessage(HttpMethod.Get, targetUrl);

        var response = await httpClient.SendAsync(request);
        response.EnsureSuccessStatusCode();

        return new ObjectResult(await response.Content.ReadAsStringAsync())
        {
            StatusCode = (int)response.StatusCode
        };
    }
}
```

